import { useEffect, useState } from 'react';
import api from '../api/client';

function AdminDashboard() {
  const [alerts, setAlerts] = useState([]);
  const [hospital, setHospital] = useState({ name: '', city: '', address: '', phone: '' });

  const loadAlerts = async () => {
    const { data } = await api.get('/admin/alerts');
    setAlerts(data);
  };

  const addHospital = async (e) => {
    e.preventDefault();
    await api.post('/admin/hospitals', hospital);
    setHospital({ name: '', city: '', address: '', phone: '' });
  };

  useEffect(() => {
    loadAlerts();
  }, []);

  return (
    <div className="container py-4">
      <h2>Admin Dashboard</h2>
      <div className="row g-3">
        <div className="col-md-4">
          <div className="card p-3 shadow-sm">
            <h5>Add Hospital</h5>
            <form onSubmit={addHospital}>
              <input className="form-control mb-2" placeholder="Name"
                value={hospital.name} onChange={(e) => setHospital({ ...hospital, name: e.target.value })} />
              <input className="form-control mb-2" placeholder="City"
                value={hospital.city} onChange={(e) => setHospital({ ...hospital, city: e.target.value })} />
              <input className="form-control mb-2" placeholder="Address"
                value={hospital.address} onChange={(e) => setHospital({ ...hospital, address: e.target.value })} />
              <input className="form-control mb-2" placeholder="Phone"
                value={hospital.phone} onChange={(e) => setHospital({ ...hospital, phone: e.target.value })} />
              <button className="btn btn-danger w-100">Add</button>
            </form>
          </div>
        </div>
        <div className="col-md-8">
          <div className="card p-3 shadow-sm">
            <h5>Recent SOS Alerts</h5>
            <div className="list-group">
              {alerts.map((a) => (
                <div key={a.id} className="list-group-item">
                  User {a.userId} | {a.location} | {new Date(a.createdAt).toLocaleString()}
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default AdminDashboard;
